        src >> 8 & 255,
        // SRCADDR[15:8]
        src & 255,
        // SRCADDR[7:0]
        dest >> 8 & 255,
        // DESTADDR[15:8]
        dest & 255,
        // DESTADDR[7:0]
        len >> 8 & 255,
        // LEN[15:8] (no VLEN bit!)
        len & 255,
        // LEN[7:0]
        18,
        // TRIG=18 (FLASH)
        66
        // SRCINC=1, DESTINC=0, PRI=0
