      await this.writeXData(_CCDebugger.XREG_DMA0CFGL, new Uint8Array([_CCDebugger.ADDR_DMA_DESC & 255]), true);
      await this.writeXData(_CCDebugger.XREG_DMA0CFGH, new Uint8Array([_CCDebugger.ADDR_DMA_DESC >> 8 & 255]), true);
