          updatedDesc[0] = bankOffset + _CCDebugger.XBANK_OFFSET >> 8 & 255;
          updatedDesc[1] = bankOffset + _CCDebugger.XBANK_OFFSET & 255;
          updatedDesc[4] = actualCount >> 8 & 255;
          updatedDesc[5] = actualCount & 255;
